class Solution:
    def minFlips(self, s):
        """
        :type s: str
        :rtype: int
        """
        n = len(s)
        min_flips = float('inf')

        # Try each rotation
        for start in range(n):
            flips = 0
            for i in range(n):
                # Two patterns: starting with 0 or 1
                expected_0 = str(i % 2)
                expected_1 = str(1 - (i % 2))

                char = s[(start + i) % n]
                if char != expected_0:
                    flips_0 = 1
                else:
                    flips_0 = 0

                if char != expected_1:
                    flips_1 = 1
                else:
                    flips_1 = 0

            # This is inefficient, better approach below

        # Better: for each pattern, count mismatches
        pattern_0 = flips_0 = flips_1 = 0
        for i, c in enumerate(s):
            expected_0 = str(i % 2)
            expected_1 = str(1 - (i % 2))
            if c != expected_0:
                flips_0 += 1
            if c != expected_1:
                flips_1 += 1

        return min(flips_0, flips_1)
